using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents still use "Discriminator", so pin the old name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change 2: EF 9 uses only the raw key for "id" (e.g. "1").
            // Existing documents have "Blog|1" format, so restore the old convention.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexing on arbitrary
            // properties. EF 9 now throws instead of silently ignoring. Remove it.
            // (HasIndex call removed)
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change 4: EF 9 enables sync I/O guard by default.
    // SyncJob.cs uses synchronous .ToList() / .SaveChanges().
    // Fix is applied in SyncJob.cs by switching to async APIs.
}

/// <summary>
/// Restores the EF Core 8 "Discriminator|Key" id format for existing documents.
/// </summary>
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var entityType = entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue;
        return $"{entityType}|{key}";
    }
}

